def integer_break(n):
    dp = [0] * (n + 1)
    dp[1] = 1
    for i in range(2, n + 1):
        best = 0
        for j in range(1, i):
            best = max(best, j * (i - j), j * dp[i - j])
        dp[i] = best
    return dp[n]

def zigzag_convert(s, numRows):
    if numRows == 1 or numRows >= len(s):
        return s
    rows = [''] * numRows
    cur = 0
    going_down = False
    for c in s:
        rows[cur] += c
        if cur == 0 or cur == numRows - 1:
            going_down = not going_down
        cur += 1 if going_down else -1
    return ''.join(rows)

