def lr_step(x, y, weights, bias, lr):
    import math
    z = sum(w * xi for w, xi in zip(weights, x)) + bias
    if z >= 0:
        p = 1 / (1 + math.exp(-z))
    else:
        ez = math.exp(z)
        p = ez / (1 + ez)
    err = p - y
    new_w = [round(w - lr * err * xi, 6) for w, xi in zip(weights, x)]
    new_b = round(bias - lr * err, 6)
    return (new_w, new_b)

