def roman_add(a, b):
    vals = {'I': 1, 'V': 5, 'X': 10, 'L': 50, 'C': 100, 'D': 500, 'M': 1000}
    def to_int(s):
        n = 0
        for i, c in enumerate(s):
            if i + 1 < len(s) and vals[c] < vals[s[i + 1]]:
                n -= vals[c]
            else:
                n += vals[c]
        return n
    def to_roman(n):
        order = [(1000,'M'),(900,'CM'),(500,'D'),(400,'CD'),(100,'C'),(90,'XC'),(50,'L'),(40,'XL'),(10,'X'),(9,'IX'),(5,'V'),(4,'IV'),(1,'I')]
        out = []
        for v, sym in order:
            while n >= v:
                out.append(sym)
                n -= v
        return ''.join(out)
    return to_roman(to_int(a) + to_int(b))

